        const fixedActiveWidgetsSpan = document.getElementById('fixedActiveWidgets');

        function updateCounters() {
            totalWidgetsCreatedSpan.textContent = totalWidgetsCreated;
            leakingActiveWidgetsSpan.textContent = leakingActiveWidgets;
            fixedActiveWidgetsSpan.textContent = fixedActiveWidgets;
        }

        // --- Buggy (Leaking) Widget Logic ---
        function createLeakingWidgetElement(id) {
            totalWidgetsCreated++;
            leakingActiveWidgets++;
            updateCounters();

            const widgetDiv = document.createElement('div');
            widgetDiv.classList.add('widget');
            widgetDiv.id = `leaking-widget-${id}`;

            const title = document.createElement('h3');
            title.textContent = `Leaking Widget #${id}`;
            widgetDiv.appendChild(title);

            const content = document.createElement('p');
            content.classList.add('widget-content');
            content.textContent = `This is leaking widget number ${id}. It attaches an event listener that captures its own DOM element and its closure is never released. Click to expand.`;
            widgetDiv.appendChild(content);

            const removeBtn = document.createElement('button');
            removeBtn.classList.add('remove-button');
            removeBtn.textContent = 'Remove';
            widgetDiv.appendChild(removeBtn);

            // *** THE LEAKING PART 1: Event listener closure ***
            // This closure captures 'widgetDiv'. When 'removeBtn' is clicked,
            // 'widgetDiv' is removed from the DOM, but this 'click' listener
            // (and its closure) on 'widgetDiv' itself is never removed.
