            // the 'widgetDiv' still has its own listener that refers to it.
            // More critically, if 'removeBtn' was stored in a global array,
            // its listener would also be a source of a leak.
            removeBtn.addEventListener('click', (event) => {
                event.stopPropagation(); // Prevent widget click from firing
                console.log(`Removing leaking widget #${id}`);
                leakingDashboard.removeChild(widgetDiv);
                leakingActiveWidgets--;
                updateCounters();
                // Crucially, no removeEventListener for widgetDiv or removeBtn
                // No nullifying of references. The widgetDiv and its internal listener
                // remain in memory because the internal listener still references widgetDiv.
            });

            return widgetDiv;
        }

        addLeakingWidgetBtn.addEventListener('click', () => {
            leakingDashboard.appendChild(createLeakingWidgetElement(Math.floor(Math.random() * 100000)));
        });


        // --- Fixed (No Leak) Widget Logic ---
        function createFixedWidgetElement(id) {
            totalWidgetsCreated++;
            fixedActiveWidgets++;
            updateCounters();

            const widgetDiv = document.createElement('div');
            widgetDiv.classList.add('widget');
            widgetDiv.id = `fixed-widget-${id}`;

            const title = document.createElement('h3');
            title.textContent = `Fixed Widget #${id}`;
            widgetDiv.appendChild(title);

            const content = document.createElement('p');
            content.classList.add('widget-content');
            content.textContent = `This is fixed widget number ${id}. Its event listeners are properly cleaned up on removal. Click to expand.`;
            widgetDiv.appendChild(content);

            const removeBtn = document.createElement('button');
            removeBtn.classList.add('remove-button');
            removeBtn.textContent = 'Remove';
            widgetDiv.appendChild(removeBtn);

            // Store the handler function reference so it can be removed later
            const widgetClickHandler = () => {
                console.log(`Fixed widget ${id} content clicked!`);
                content.classList.toggle('expanded');
            };
            widgetDiv.addEventListener('click', widgetClickHandler);

            // Store the handler function reference for the remove button too
            const removeBtnClickHandler = (event) => {
                event.stopPropagation(); // Prevent widget click from firing
                console.log(`Removing fixed widget #${id}`);

                // *** THE FIX 1: Remove event listeners ***
                widgetDiv.removeEventListener('click', widgetClickHandler);
                removeBtn.removeEventListener('click', removeBtnClickHandler); // Good practice to remove this too

                fixedDashboard.removeChild(widgetDiv);
                fixedActiveWidgets--;
                updateCounters();

                // *** THE FIX 2: (Implicit) Nullify references if they existed ***
                // In this case, since widgetDiv and removeBtn are local to this function scope
                // and not stored in any global array, once they are removed from the DOM
                // and their listeners are removed, they become unreachable and eligible for GC.
            };
            removeBtn.addEventListener('click', removeBtnClickHandler);

            return widgetDiv;
        }

        addFixedWidgetBtn.addEventListener('click', () => {
            fixedDashboard.appendChild(createFixedWidgetElement(Math.floor(Math.random() * 100000)));
        });

        // Initialize counters on load
        updateCounters();
    </script>
</body>
</html>
