                const lastWidget = fixedWidgets.pop(); // Remove reference from our array
                const widgetId = parseInt(lastWidget.dataset.widgetId);

                // THIS IS THE FIX: Remove the event listener
                const listenerInfo = fixedWidgetListeners.get(widgetId);
                if (listenerInfo) {
                    listenerInfo.element.removeEventListener('click', listenerInfo.listener);
                    fixedWidgetListeners.delete(widgetId); // Remove listener info from our map
                    console.log(`Removed listener for Fixed Widget ${widgetId}`);
                }

                fixedWidgetGrid.removeChild(lastWidget); // Remove from DOM
                // Now, 'lastWidget' and its associated data are no longer reachable (assuming no other references)
                // and can be garbage collected.
            }
            updateFixedWidgetCount();
        }

        function updateFixedWidgetCount() {
            fixedWidgetCountSpan.textContent = fixedWidgetGrid.children.length;
        }
    </script>
