    <script>
        // --- Buggy Dashboard Logic ---
        const buggyDashboard = document.getElementById('buggyDashboard');
        const buggyWidgetCountSpan = document.getElementById('buggyWidgetCount');
        let buggyWidgetIdCounter = 0;
        const buggyWidgetsData = []; // This array will hold references to widgets that are "removed" but not GC'd

        function createBuggyWidget() {
            buggyWidgetIdCounter++;
            const widgetId = `buggy-widget-${buggyWidgetIdCounter}`;
            const widgetDiv = document.createElement('div');
            widgetDiv.className = 'widget';
            widgetDiv.id = widgetId;
            widgetDiv.innerHTML = `
                <h3>Buggy Widget ${buggyWidgetIdCounter}</h3>
                <p>Value: <span class="value">0</span></p>
                <button class="increment-btn">Increment</button>
            `;

            const incrementBtn = widgetDiv.querySelector('.increment-btn');
            const valueSpan = widgetDiv.querySelector('.value');
            let value = 0;

            // BUG: Event listener is added directly, but never removed.
            // When widgetDiv is removed from DOM, this listener still exists
            // and holds a reference to widgetDiv, valueSpan, and the closure's scope.
            incrementBtn.addEventListener('click', function buggyIncrementHandler() {
                value++;
                valueSpan.textContent = value;
                // Imagine more complex data or API calls here
                console.log(`Buggy Widget ${widgetId} incremented to ${value}`);
            });

            // BUG: We store a reference to the DOM element in an array,
            // even after it's "removed" from the dashboard.
            // This prevents the GC from collecting it.
            buggyWidgetsData.push({
                id: widgetId,
                element: widgetDiv, // Keeping a direct reference here!
                // Potentially other data related to the widget
                // The incrementHandler closure also implicitly holds a reference to widgetDiv and valueSpan
            });

            buggyDashboard.appendChild(widgetDiv);
            updateBuggyWidgetCount();
        }

        function removeBuggyWidget() {
            if (buggyDashboard.lastChild) {
                const removedElement = buggyDashboard.lastChild;
                buggyDashboard.removeChild(removedElement);

                // BUG: We DON'T remove the event listener.
                // The `buggyIncrementHandler` (defined anonymously or directly)
                // continues to exist and holds a reference to `removedElement`
                // and its internal `valueSpan` and `value` variable via closure.
                // This means the DOM element itself cannot be garbage collected.

                // BUG: We also DON'T remove the reference from `buggyWidgetsData`.
                // Even if we removed the element from the DOM, if this array still
                // holds `removedElement`, it's still reachable.
                // For demonstration, let's pretend we "cleaned" `buggyWidgetsData`
                // by popping, but the listener is the primary leak.
                buggyWidgetsData.pop(); // This only removes the last item from our tracking array.
                                        // The actual DOM element and its listeners are the leak.

                updateBuggyWidgetCount();
            }
        }

        function resetBuggyDashboard() {
            while (buggyDashboard.firstChild) {
                buggyDashboard.removeChild(buggyDashboard.firstChild);
            }
            // In a real app, you'd also need to explicitly clean up any event listeners
            // or lingering references from `buggyWidgetsData` here if they weren't
            // cleaned on individual removal.
            buggyWidgetsData.length = 0; // Clear the array, but listeners on detached elements might still exist.
            buggyWidgetIdCounter = 0;
            updateBuggyWidgetCount();
        }

        function updateBuggyWidgetCount() {
            buggyWidgetCountSpan.textContent = buggyDashboard.children.length;
        }

        document.getElementById('addBuggyWidget').addEventListener('click', createBuggyWidget);
        document.getElementById('removeBuggyWidget').addEventListener('click', removeBuggyWidget);
        document.getElementById('resetBuggyDashboard').addEventListener('click', resetBuggyDashboard);


        // --- Fixed Dashboard Logic ---
        const fixedDashboard = document.getElementById('fixedDashboard');
        const fixedWidgetCountSpan = document.getElementById('fixedWidgetCount');
        let fixedWidgetIdCounter = 0;

        // In the fixed version, we don't need a global array to track widget DOM elements
        // because we'll ensure they are properly cleaned up and GC'd.
        // If we *did* need to track data, we'd store plain data objects, not DOM elements.

        // We'll use a WeakMap to store event listener handlers linked to their elements.
        // A WeakMap allows its keys to be garbage-collected if there are no other references to them.
        // This is a good pattern for managing event listeners when you can't explicitly remove them
        // by reference (e.g., if you're using an anonymous function).
        // However, the best practice is to always store the handler function reference and remove it.
        // For this demo, let's explicitly remove the handler.
        const fixedWidgetHandlers = new Map(); // Store references to handler functions

        function createFixedWidget() {
            fixedWidgetIdCounter++;
            const widgetId = `fixed-widget-${fixedWidgetIdCounter}`;
            const widgetDiv = document.createElement('div');
            widgetDiv.className = 'widget';
            widgetDiv.id = widgetId;
            widgetDiv.innerHTML = `
                <h3>Fixed Widget ${fixedWidgetIdCounter}</h3>
                <p>Value: <span class="value">0</span></p>
                <button class="increment-btn">Increment</button>
            `;

            const incrementBtn = widgetDiv.querySelector('.increment-btn');
            const valueSpan = widgetDiv.querySelector('.value');
            let value = 0;

            // FIX: Define the event listener function *by name* or reference
            // so we can remove it later.
            function fixedIncrementHandler() {
                value++;
                valueSpan.textContent = value;
                console.log(`Fixed Widget ${widgetId} incremented to ${value}`);
            }

            incrementBtn.addEventListener('click', fixedIncrementHandler);

            // Store a reference to the handler function, associated with the widget's DOM element.
            // This is crucial for removal.
            fixedWidgetHandlers.set(widgetDiv, fixedIncrementHandler);

            fixedDashboard.appendChild(widgetDiv);
            updateFixedWidgetCount();
        }

        function removeFixedWidget() {
            if (fixedDashboard.lastChild) {
                const removedElement = fixedDashboard.lastChild;

                // FIX: Retrieve the stored handler and explicitly remove the event listener.
                const handler = fixedWidgetHandlers.get(removedElement);
                if (handler) {
                    removedElement.querySelector('.increment-btn').removeEventListener('click', handler);
                    fixedWidgetHandlers.delete(removedElement); // Remove reference from our tracking map
                }

                // Now that the event listener reference is gone, and no other code
                // holds a reference to `removedElement`, it can be garbage collected
                // once it's removed from the DOM.
                fixedDashboard.removeChild(removedElement);
                updateFixedWidgetCount();
            }
        }

        function resetFixedDashboard() {
            // FIX: Iterate through all children to ensure all listeners are removed.
            Array.from(fixedDashboard.children).forEach(widgetDiv => {
                const handler = fixedWidgetHandlers.get(widgetDiv);
                if (handler) {
                    widgetDiv.querySelector('.increment-btn').removeEventListener('click', handler);
                    fixedWidgetHandlers.delete(widgetDiv);
                }
            });

            while (fixedDashboard.firstChild) {
                fixedDashboard.removeChild(fixedDashboard.firstChild);
            }
            fixedWidgetIdCounter = 0;
            updateFixedWidgetCount();
        }

        function updateFixedWidgetCount() {
            fixedWidgetCountSpan.textContent = fixedDashboard.children.length;
        }

        document.getElementById('addFixedWidget').addEventListener('click', createFixedWidget);
        document.getElementById('removeFixedWidget').addEventListener('click', removeFixedWidget);
        document.getElementById('resetFixedDashboard').addEventListener('click', resetFixedDashboard);
    </script>
</body>
