                    // In a real app, you'd also remove event listeners attached to global objects
                    // or other objects outside its own DOM subtree.
                    console.log(`Widget ${this.id} (type: ${isLeaking ? 'leaking' : 'fixed'}) destroyed its internal state.`);
                }
            };
            return widget;
        }

        // --- Widget Creation Functions ---
        function createWidgetDOM(widgetId, isLeaking) {
            const widgetDiv = document.createElement('div');
            widgetDiv.className = `widget ${isLeaking ? 'widget-leaking' : ''}`;
            widgetDiv.id = `widget-${widgetId}-${isLeaking ? 'leaking' : 'fixed'}`;
            widgetDiv.innerHTML = `
                <div class="widget-header">
                    <span>Widget #${widgetId}</span>
                    <button class="remove-widget-btn" data-widget-id="${widgetId}" data-is-leaking="${isLeaking}">&times;</button>
                </div>
                <div class="widget-content">0</div>
            `;

            // Attach remove listener. This is where the leak happens for the buggy version
            // if we don't clean it up or if 'this' (the widget object) is implicitly captured.
            // For simplicity, we attach to the button, but in a real app, the widget object
            // would manage its own internal listeners and DOM elements.
            const removeBtn = widgetDiv.querySelector('.remove-widget-btn');
            removeBtn.addEventListener('click', (event) => {
                const idToRemove = parseInt(event.target.dataset.widgetId);
                const isLeakingBtn = event.target.dataset.isLeaking === 'true';

                if (isLeakingBtn) {
                    removeLeakingWidget(idToRemove);
                } else {
                    removeFixedWidget(idToRemove);
                }
            });

            return widgetDiv;
        }

        // --- Leaking Dashboard Logic ---
        function addLeakingWidget() {
            leakingWidgetCount++;
            const widgetId = leakingWidgetCount;
            const widgetObj = createWidgetObject(widgetId, true);
            const widgetDOM = createWidgetDOM(widgetId, true);

            leakingWidgetGrid.appendChild(widgetDOM);
            widgetObj.startUpdating(widgetDOM);

            // THE LEAK: Storing a reference to the widget object in a global array.
            // When the DOM element is removed, this reference keeps the widget object
            // and its associated DOM element (which still has its internal interval)
            // reachable, preventing GC.
            leakingWidgetInstances.push(widgetObj);

            updateCounts();
            console.log(`Leaking widget #${widgetId} added.`);
        }

        function removeLeakingWidget(idToRemove) {
            const widgetDOM = document.getElementById(`widget-${idToRemove}-leaking`);
            if (widgetDOM) {
                widgetDOM.remove(); // Remove from DOM
                // We DON'T remove the object from `leakingWidgetInstances` here
                // We DON'T call a destroy method on the widget object
                // The object and its interval continue to exist and consume memory!
                console.warn(`Leaking widget #${idToRemove} DOM removed. OBJECT REFERENCE and INTERVAL STILL EXIST IN MEMORY.`);
            }
            // Decrement the *displayed* count, but the actual objects are still around
            leakingWidgetCount--;
            updateCounts();
        }


        function removeAllLeakingWidgets() {
            // Remove all DOM elements
            leakingWidgetGrid.innerHTML = '';

            // THE LEAK: We do NOT clear the leakingWidgetInstances array.
            // All widget objects created are still referenced here, keeping them
            // and their associated DOM elements (even if detached) alive.
            // Their intervals continue to run in the background!
            console.error(`ALL LEAKING WIDGET DOM ELEMENTS REMOVED. ${leakingWidgetInstances.length} widget objects and their intervals are still active in memory!`);

            leakingWidgetCount = 0; // Reset displayed count
            updateCounts();
        }

        // --- Fixed Dashboard Logic ---
        function addFixedWidget() {
            fixedWidgetCount++;
            const widgetId = fixedWidgetCount;
            const widgetObj = createWidgetObject(widgetId, false);
            const widgetDOM = createWidgetDOM(widgetId, false);

            fixedWidgetGrid.appendChild(widgetDOM);
            widgetObj.startUpdating(widgetDOM);

            // Store the widget object. We will clean this up.
            fixedWidgetInstances.push(widgetObj);

            updateCounts();
            console.log(`Fixed widget #${widgetId} added.`);
        }

        function removeFixedWidget(idToRemove) {
            const widgetDOM = document.getElementById(`widget-${idToRemove}-fixed`);
            if (widgetDOM) {
                widgetDOM.remove(); // Remove from DOM

                // Find and destroy the corresponding widget object
                const index = fixedWidgetInstances.findIndex(w => w.id === idToRemove);
                if (index > -1) {
                    fixedWidgetInstances[index].destroy(); // CALL THE DESTROY METHOD!
                    fixedWidgetInstances.splice(index, 1); // Remove from our tracking array
                    console.log(`Fixed widget #${idToRemove} DOM removed and object destroyed/dereferenced.`);
                }
            }
            fixedWidgetCount--;
            updateCounts();
        }

        function removeAllFixedWidgets() {
            // Remove all DOM elements
            fixedWidgetGrid.innerHTML = '';

            // THE FIX: Iterate through all widget objects and call their destroy method,
            // then clear the array that holds references to them.
            fixedWidgetInstances.forEach(widget => widget.destroy());
            fixedWidgetInstances = []; // Crucial: clear the array of references!

            console.info(`All fixed widget DOM elements removed and ${fixedWidgetInstances.length} widget objects destroyed/dereferenced. Memory should be reclaimed.`);

            fixedWidgetCount = 0;
            updateCounts();
        }

        // --- Update Counters ---
        function updateCounts() {
            leakingWidgetCountDisplay.textContent = Math.max(0, leakingWidgetCount);
            leakingGhostCountDisplay.textContent = leakingWidgetInstances.length; // This will grow!

            fixedWidgetCountDisplay.textContent = Math.max(0, fixedWidgetCount);
            fixedGhostCountDisplay.textContent = fixedWidgetInstances.length; // This should shrink to 0
        }

        // Initial count update
        updateCounts();

        // Periodically log memory usage (approximate, for demonstration)
        // In a real scenario, you'd use browser dev tools for accurate measurements.
        setInterval(() => {
            if (window.performance && window.performance.memory) {
                const usedJSHeap = (performance.memory.usedJSHeapSize / (1024 * 1024)).toFixed(2);
                const totalJSHeap = (performance.memory.totalJSHeapSize / (1024 * 1024)).toFixed(2);
                // console.log(`JS Heap: ${usedJSHeap} MB / ${totalJSHeap} MB`);
            }
        }, 5000); // Log every 5 seconds
    </script>
